import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.1N8rnUr9.js";const f=JSON.parse('{"title":"Request a Feature","description":"","frontmatter":{},"headers":[],"relativePath":"feature-request.md","filePath":"feature-request.md","lastUpdated":1775715475000}'),s={name:"feature-request.md"};function i(n,e,l,u,h,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="request-a-feature" tabindex="-1">Request a Feature <a class="header-anchor" href="#request-a-feature" aria-label="Permalink to &quot;Request a Feature&quot;">​</a></h1><p>We want to hear from you! If you have an idea for a new feature or an improvement to TubeBay, please let us know.</p><h2 id="how-to-submit-a-request" tabindex="-1">How to Submit a Request <a class="header-anchor" href="#how-to-submit-a-request" aria-label="Permalink to &quot;How to Submit a Request&quot;">​</a></h2><ol><li>Visit the <a href="https://github.com/wpanchorbay/tubebay/issues" target="_blank" rel="noreferrer">GitHub Issues page</a>.</li><li>Click <strong>New Issue</strong> and select the <strong>Feature Request</strong> template (if available) or choose <strong>Blank Issue</strong>.</li><li>Clearly describe the feature: <ul><li><strong>What problem does it solve?</strong></li><li><strong>How should it work?</strong></li><li><strong>Who would benefit from it?</strong></li></ul></li></ol><h2 id="what-and-what-not-to-request" tabindex="-1">What and What Not to Request <a class="header-anchor" href="#what-and-what-not-to-request" aria-label="Permalink to &quot;What and What Not to Request&quot;">​</a></h2><h3 id="✅-what-we-love" tabindex="-1">✅ What We Love: <a class="header-anchor" href="#✅-what-we-love" aria-label="Permalink to &quot;✅ What We Love:&quot;">​</a></h3><ul><li>Ideas for new mapping strategies.</li><li>Support for additional video platforms (Vimeo, etc.).</li><li>Improved UI/UX for the mapping dashboard.</li><li>New placement locations for the video player.</li></ul><h3 id="❌-what-not-to-request" tabindex="-1">❌ What Not to Request: <a class="header-anchor" href="#❌-what-not-to-request" aria-label="Permalink to &quot;❌ What Not to Request:&quot;">​</a></h3><ul><li><strong>Support Requests:</strong> For help or bugs, use the <a href="https://wordpress.org/support/plugin/tubebay/" target="_blank" rel="noreferrer">support forum</a> instead.</li><li><strong>Vague Ideas:</strong> Try to be as specific as possible.</li><li><strong>Duplicate Requests:</strong> Search existing issues before opening a new one.</li></ul><h2 id="what-happens-next" tabindex="-1">What Happens Next? <a class="header-anchor" href="#what-happens-next" aria-label="Permalink to &quot;What Happens Next?&quot;">​</a></h2><p>The TubeBay team and the community will review your request. We prioritize features based on:</p><ul><li><strong>Demand:</strong> How many other users want this?</li><li><strong>Effort:</strong> How complex is the implementation?</li><li><strong>Alignment:</strong> Does it fit the core vision of TubeBay?</li></ul><p>Thank you for helping make TubeBay better! 🙏</p>',13)])])}const m=t(s,[["render",i]]);export{f as __pageData,m as default};
